  const browser = await chromium.launch();
  const page = await browser.newPage();
  const errors = [];
  page.on('console', msg => { if (msg.type() === 'error' || msg.type() === 'warn') errors.push('[' + msg.type() + '] ' + msg.text().substring(0, 300)); });
