      // SuperApp mocks: specific ~/... aliases must come BEFORE the generic ~ alias
      { find: '~/store', replacement: path.resolve(__dirname, 'mocks/store.ts') },
      { find: '~/redux/store/storage', replacement: path.resolve(__dirname, 'mocks/redux-store-storage.ts') },
      { find: '~', replacement: path.resolve(__dirname, '../src') },
      // Native module mocks
