      { find: 'react-native-linear-gradient', replacement: path.resolve(__dirname, 'mocks/react-native-linear-gradient.tsx') },
      { find: 'react-native-modalize', replacement: path.resolve(__dirname, 'mocks/react-native-modalize.tsx') },
      { find: 'react-native-skeleton-placeholder', replacement: path.resolve(__dirname, 'mocks/react-native-skeleton-placeholder.tsx') },
      { find: '@react-native-community/slider', replacement: path.resolve(__dirname, 'mocks/react-native-community-slider.tsx') },
      { find: 'lottie-react-native', replacement: path.resolve(__dirname, 'mocks/lottie-react-native.tsx') },
